import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Login from './components/Login';
import Register from './components/Register';
import LeadList from './components/LeadList';

function App() {
  const [user, setUser] = useState(null);

  const handleLogin = (token, userData) => {
    setUser(userData);
  };

  const handleRegister = (token, userData) => {
    setUser(userData);
  };

  const fetchLeads = async (params = {}) => {
    try {
      const query = new URLSearchParams(params).toString();
      const token = localStorage.getItem("token"); // ✅ read token
      const res = await axios.get(`http://localhost:5000/api/leads?${query}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      console.log("Leads:", res.data.leads);
    } catch (err) {
      console.error("Error fetching leads:", err);
    }
  };

  useEffect(() => {
    if (user) {
      fetchLeads();
    }
  }, [user]);

  return (
    <div>
      {!user ? (
        <>
          <Login onLogin={handleLogin} onSwitchToRegister={() => {}} />
          <Register onRegister={handleRegister} onSwitchToLogin={() => {}} />
        </>
      ) : (
        <LeadList />
      )}
    </div>
  );
}

export default App;
